:host { display: block; }
.agent-activity { border: var(--dimension-stroke-width-012) solid var(--color-border-tertiary); border-radius: var(--dimension-radius-050); }
summary { align-items: center; cursor: pointer; display: flex; gap: var(--dimension-space-050); list-style: none; padding: var(--dimension-space-075) var(--dimension-space-100); }
summary::-webkit-details-marker { display: none; }
details[open] summary ds-icon { transform: rotate(90deg); }
ol { display: grid; gap: var(--dimension-space-075); list-style: none; margin: 0; padding: 0 var(--dimension-space-100) var(--dimension-space-100); }
.agent-activity__item { align-items: start; display: grid; gap: var(--dimension-space-050); grid-template-columns: auto minmax(0, 1fr); }
.agent-activity__marker { align-items: center; color: var(--color-foreground-faint-neutral); display: flex; padding-block-start: var(--dimension-space-025); }
.agent-activity__item--active .agent-activity__marker { color: var(--color-foreground-faint-brand); }
.agent-activity__item--error .agent-activity__marker { color: var(--color-foreground-bold-negative); }
.agent-activity__item span:last-child { display: grid; gap: var(--dimension-space-025); }

@media (prefers-reduced-motion: no-preference) { summary ds-icon { transition: transform var(--effect-motion-short-2); } }

import { Component, Prop, h, Host } from '@stencil/core';
import type { AgentActivityItem } from '../conversation-types';

@Component({
  tag: 'ds-agent-activity',
  styleUrl: 'AgentActivity.css',
  scoped: true,
})
export class AgentActivity {
  @Prop() items: AgentActivityItem[] = [];
  @Prop() heading: string = 'Activity';
  @Prop() open: boolean = false;

  render() {
    return (
      <Host>
        <details class="agent-activity" open={this.open}>
          <summary>
            <ds-icon name="ChevronRight" size="xs" color="inherit" />
            <ds-text variant="text-body-small" emphasis>{this.heading}</ds-text>
          </summary>
          <ol>
            {this.items.map(item => (
              <li class={`agent-activity__item agent-activity__item--${item.state}`}>
                <span class="agent-activity__marker" aria-hidden="true">
                  {item.state === 'active'
                    ? <ds-loader size="xs" color="inherit" />
                    : <ds-icon name={item.state === 'error' ? 'ErrorTriangle' : 'Check'} size="xs" color="inherit" />}
                </span>
                <span>
                  <ds-text variant="text-body-small" emphasis={item.state === 'active'}>{item.label}</ds-text>
                  {item.detail ? <ds-text variant="text-caption" color="secondary">{item.detail}</ds-text> : null}
                </span>
              </li>
            ))}
          </ol>
        </details>
      </Host>
    );
  }
}
